package handlers

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"testing"
)

func TestWriteResult(t *testing.T) {
	recorder := httptest.NewRecorder()

	err := WriteResult(recorder, http.StatusCreated, map[string]int{"value": 7})
	if err != nil {
		t.Fatalf("WriteResult returned error: %v", err)
	}

	if recorder.Code != http.StatusCreated {
		t.Fatalf("expected status 201, got %d", recorder.Code)
	}

	if contentType := recorder.Header().Get("Content-Type"); contentType != "application/json" {
		t.Fatalf("expected application/json content type, got %q", contentType)
	}

	var response SuccessEnvelope[map[string]int]
	if err := json.Unmarshal(recorder.Body.Bytes(), &response); err != nil {
		t.Fatalf("decode response: %v", err)
	}

	if !response.OK {
		t.Fatalf("expected ok=true, got false")
	}

	if response.Result["value"] != 7 {
		t.Fatalf("expected result value 7, got %d", response.Result["value"])
	}
}

func TestWriteBusinessFailure(t *testing.T) {
	recorder := httptest.NewRecorder()

	err := WriteBusinessFailure(recorder, ReasonValidationFailed)
	if err != nil {
		t.Fatalf("WriteBusinessFailure returned error: %v", err)
	}

	if recorder.Code != http.StatusOK {
		t.Fatalf("expected status 200, got %d", recorder.Code)
	}

	var response FailureEnvelope
	if err := json.Unmarshal(recorder.Body.Bytes(), &response); err != nil {
		t.Fatalf("decode response: %v", err)
	}

	if response.OK {
		t.Fatalf("expected ok=false, got true")
	}

	if response.Reason != string(ReasonValidationFailed) {
		t.Fatalf("expected reason %q, got %q", ReasonValidationFailed, response.Reason)
	}
}

package handlers

import (
	"encoding/json"
	"net/http"
)

type FailureReason string

const (
	ReasonValidationFailed FailureReason = "VALIDATION_FAILED"
	ReasonInternalError    FailureReason = "INTERNAL_ERROR"
)

type SuccessEnvelope[T any] struct {
	OK     bool `json:"ok"`
	Result T    `json:"result"`
}

type FailureEnvelope struct {
	OK     bool   `json:"ok"`
	Reason string `json:"reason"`
}

func WriteResult[T any](w http.ResponseWriter, statusCode int, result T) error {
	return writeJSON(w, statusCode, SuccessEnvelope[T]{
		OK:     true,
		Result: result,
	})
}

func WriteFailure(w http.ResponseWriter, statusCode int, reason FailureReason) error {
	return writeJSON(w, statusCode, FailureEnvelope{
		OK:     false,
		Reason: string(reason),
	})
}

func WriteBusinessFailure(w http.ResponseWriter, reason FailureReason) error {
	return WriteFailure(w, http.StatusOK, reason)
}

func writeJSON(w http.ResponseWriter, statusCode int, payload any) error {
	body, err := json.Marshal(payload)
	if err != nil {
		return err
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(statusCode)
	_, err = w.Write(append(body, '\n'))
	return err
}
